import { Vex } from '@vex/sdk';
import express from 'express';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });
const app = express();
app.use(express.json());

app.post('/vex-webhook', async (req, res) => {
  const event = req.body;

  if (event.type === 'run.completed') {
    const { id: runId, thread_id: threadId } = event.data;

    const messages = await openai.beta.threads.messages.list(threadId);
    const researchOutput = messages.data[0].content[0].text?.value;

    const result = await vex.verify({
      input: researchOutput,
      useCase: 'research_agent',
      verifications: [
        'source_verification',
        'claim_accuracy',
        'recency_checks',
        'bias_detection'
      ]
    });

    if (!result.verified) {
      // Auto-refine failed research
      await openai.beta.threads.runs.create(threadId, {
        assistant_id: assistant.id,
        instructions: `Refine research addressing: ${result.issues}`
      });
    }
  }

  res.status(200).send('OK');
});

policy = vex.policies.create(
    name="research_source_policy",
    use_case="research_agent",
    verifications=[
        {
            "type": "source_verification",
            "config": {
                "require_urls": True,
                "check_domain_authority": True,
                "min_sources_per_claim": 2
            }
        },
        {
            "type": "recency_checks",
            "config": {
                "max_age_days": 365,
                "priority_domains": [".edu", ".gov", ".org"]
            }
        },
        {
            "type": "bias_detection",
            "config": {
                "threshold": "medium",
                "check_language_sentiment": True
            }
        }
    ]
)

# Apply to all research threads
vex.apply_policy(policy.id, "openai_research_threads")
